function fmtDataHoje() {
  const hoje = new Date();
  const dd = String(hoje.getDate()).padStart(2, '0');
  const mm = String(hoje.getMonth() + 1).padStart(2, '0');
  const yyyy = hoje.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

// entradas:
// items[0] → { numero }  (vem do update returning do Supabase)
// items[1] → { id_cliente, produtos[] }
// items[2] → { data: [...] } catálogo detalhado dos produtos

const sequencial = items[0].json.numero;
const cliente = items[1].json;
const catalogo = items[2].json.data;

const codigoPedido = `IA-${String(sequencial).padStart(6, '0')}`;
const dataHoje = fmtDataHoje();

const itensPedido = cliente.produtos.map((p, idx) => {
  const detalhe = catalogo.find(c => c.codigo === p.codigo_produto);
  if (!detalhe) throw new Error(`Produto não encontrado: ${p.codigo_produto}`);

  const tabela = detalhe.tabelasPreco.find(t => t.id === 126);
  if (!tabela) throw new Error(`Produto ${p.codigo_produto} sem tabela de preço 126`);

  const valor = parseFloat(tabela.preco.replace(".", "").replace(",", "."));

  return {
    idProduto: detalhe.id,
    idTabelaPreco: tabela.id,
    idTipoMovimentacao: 35,
    idUnidadeMedida: detalhe.idUnidadeMedida,
    item: idx + 1,
    quantidade: p.quantidade,
    valorUnitario: valor,
    dataEntrega: dataHoje
  };
});

const pedido = {
  codigoPedido,
  dataEmissao: dataHoje,
  idEmpresa: 1,
  idPessoaCliente: Number(cliente.id_cliente),
  idTipoMovimentacao: 35,
  idTipoPedido: 1,
  itensPedido
};

return [{ json: pedido }];

function fmtDataHoje() {
  const hoje = new Date();
  const dd = String(hoje.getDate()).padStart(2, '0');
  const mm = String(hoje.getMonth() + 1).padStart(2, '0');
  const yyyy = hoje.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

function fmtDataValidade() {
  const validade = new Date();
  validade.setDate(validade.getDate() + 15);
  const dd = String(validade.getDate()).padStart(2, '0');
  const mm = String(validade.getMonth() + 1).padStart(2, '0');
  const yyyy = validade.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

// Merge traz 4 items:
// items[0] → { numero }         (SQL sequence)
// items[1] → { codigo }         (idContato via BUSCA CNPJ1)
// items[2] → { data: [...] }    (catálogo de produtos)
// items[3] → { id_cliente, produtos[] }  (dados originais do trigger)

const sequencial = items[0].json.numero;
const idContato = Number(items[1].json.codigo);
const catalogo = items[2].json.data;
const cliente = items[3].json;

const codigoProposta = `IA-${String(sequencial).padStart(6, '0')}`;
const dataHoje = fmtDataHoje();
const dataValidade = fmtDataValidade();

const itensProposta = cliente.produtos.map(p => {
  const detalhe = catalogo.find(c => c.codigo === p.codigo_produto);
  if (!detalhe) throw new Error(`Produto não encontrado: ${p.codigo_produto}`);

  const tabela = detalhe.tabelasPreco.find(t => t.id === 126);
  if (!tabela) throw new Error(`Produto ${p.codigo_produto} sem tabela de preço 126`);

  const valor = parseFloat(tabela.preco.replace('.', '').replace(',', '.'));

  return {
    idProduto: detalhe.id,
    idTabelaPreco: tabela.id,
    idTipoMovimentacao: 35,
    idUnidadeMedida: detalhe.idUnidadeMedida,
    qtde: String(p.quantidade),
    valorUnitario: valor.toFixed(2),
    prazoEntregaDias: 10
  };
});

const proposta = {
  proposta: codigoProposta,
  dataEmissao: `${dataHoje} 00:00:00`,
  dataValidade: `${dataValidade} 23:59:59`,
  idEmpresa: 2,
  prazoEntrega: "30",
  idCliente: Number(cliente.id_cliente),
  idContato: idContato,
  idTipoMovimentacao: 35,
  idCondicaoPagamento: 1,
  itensProposta
};

return [{ json: proposta }];

